Author: Ray Wang <853602630@qq.com>
Date:   Tue May 26 10:49:43 2026 +0800

    Add fence.proxy.async.shared::cta between mbarrier wait and TMA load. (#642)

    * Add fence.proxy.async.shared::cta between mbarrier wait and TMA load.

    * Move fence before "mbarrier_arrive"
---
 csrc/kernels/legacy/internode_ll.cu | 2 +-
 csrc/kernels/legacy/utils.cuh       | 9 +++++++++
 2 files changed, 10 insertions(+), 1 deletion(-)

diff --git a/csrc/kernels/legacy/internode_ll.cu b/csrc/kernels/legacy/internode_ll.cu
index 9ede8e4..38ff722 100644
--- a/csrc/kernels/legacy/internode_ll.cu
+++ b/csrc/kernels/legacy/internode_ll.cu
@@ -1113,7 +1113,7 @@ LOW_LATENCY_COMBINE_RECV:
                             false,
                             topk_weight);
                     }
-
+                    fence_view_async_shared();
                     if (elect_one_sync())
                         mbarrier_arrive(empty_barriers[stage_idx]);
                     stage_idx = (stage_idx + 1) % kNumStages;
diff --git a/csrc/kernels/legacy/utils.cuh b/csrc/kernels/legacy/utils.cuh
index d6ee6a4..a28d8b8 100644
--- a/csrc/kernels/legacy/utils.cuh
+++ b/csrc/kernels/legacy/utils.cuh
@@ -382,6 +382,15 @@ __device__ __forceinline__ void tma_store_fence() {
     asm volatile("fence.proxy.async.shared::cta;");
 }

+__device__ __forceinline__ void fence_view_async_shared() {
+    asm volatile (
+        "{\n\t"
+        "fence.proxy.async.shared::cta; \n"
+        "}"
+        ::
+        : "memory");
+}
+
 constexpr uint64_t kEvictFirst = 0x12f0000000000000;
 constexpr uint64_t kEvictNormal = 0x1000000000000000;

